@pure
fn severityForLevel(level: Text) -> Int {
    if level == "info" {
        ret 1;
    }
    if level == "warning" {
        ret 2;
    }
    if level == "error" {
        ret 3;
    }
    ret 1;
}

type Summary {
    issues: Int;

    fn addIssue() -> Void {
        self.issues = self.issues + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("toon unavailable");
        }
        ret;
    }
    let doc: ToonDoc = toon_parse_file("config.json");
    let root: ToonNode = toon_root(doc);
    let server: ToonNode = toon_key(root, "server");
    let app: ToonNode = toon_key(root, "app");
    let log: ToonNode = toon_key(root, "log");
    let port: Int = toon_get_int_or(server, "port", 0);
    let appName: Text = toon_get_text_or(app, "name", "");
    let logLevel: Text = toon_get_text_or(log, "level", "info");
    let summary: Summary = new Summary();
    if !validPort(port) {
        summary.addIssue();
        fx {
            print("ISSUE: port is invalid (");
            print(port);
            println(")");
        }
    }
    if !validName(appName) {
        summary.addIssue();
        fx {
            println("ISSUE: app name is empty or too long");
        }
    }
    fx {
        println("log severity level: ", severityForLevel(logLevel));
    }
    if summary.issues > 0 {
        fx {
            println("VALIDATION FAILED: ", summary.issues, " issue(s) found");
        }
        toon_close(doc);
        ret;
    }
    fx {
        println("CONFIG VALID");
    }
    toon_close(doc);
    ret;
}

@pure
fn clampScore(raw: Int) -> Int {
    if raw < 0 {
        ret 0;
    }
    if raw > 100 {
        ret 100;
    }
    ret raw;
}

@pure
fn classifyLane(score: Int) -> Text {
    if score >= 90 {
        ret "green";
    }
    if score >= 70 {
        ret "yellow";
    }
    ret "red";
}

@pure
fn isBlocked(blockers: Int) -> Bool {
    if blockers > 0 {
        ret true;
    }
    ret false;
}

type Board {
    count: Int;
    total: Int;
    green: Int;
    yellow: Int;
    red: Int;
    blocked: Int;

    fn record(lane: Text, blocked: Bool, score: Int) -> Void {
        self.count = self.count + 1;
        self.total = self.total + score;
        if blocked {
            self.blocked = self.blocked + 1;
        }
        if lane == "green" {
            self.green = self.green + 1;
            ret;
        }
        if lane == "yellow" {
            self.yellow = self.yellow + 1;
            ret;
        }
        self.red = self.red + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() {
        fx {
            println("toon unavailable");
        }
        ret;
    }
    let doc: ToonDoc = toon_parse_file("releases.json");
    let root: ToonNode = toon_root(doc);
    let releases: ToonNode = toon_key(root, "releases");
    let board: Board = new Board();
    loop i in 0..toon_len(releases) {
        let rel: ToonNode = toon_at(releases, i);
        let id: Text = toon_get_text_or(rel, "id", "UNKNOWN");
        let raw: Int = toon_get_int_or(rel, "score", 0);
        let blockers: Int = toon_get_int_or(rel, "blockers", 0);
        let score: Int = clampScore(raw);
        let lane: Text = classifyLane(score);
        let blocked: Bool = isBlocked(blockers);
        board.record(lane, blocked, score);
        fx {
            println("release ", i, ": ", id, " / ", lane, " / ", blocked, " / ", score);
        }
    }
    let average: Real = 0.0;
    if board.count > 0 {
        average = board.total * 1.0 / board.count;
    }
    fx {
        println("green = ", board.green);
        println("yellow = ", board.yellow);
        println("red = ", board.red);
        println("blocked = ", board.blocked);
        println("average = ", average:0:2);
    }
    toon_close(doc);
    ret;
}

